SELECT b.book_id, b.book_title, b.author_name, b.publisher, b.publish_date, b.book_price, CASE WHEN b.book_stock = 0 THEN '품절' ELSE b.stock_status END AS stock_status, b.book_summary, b.cover_image, b.category_id, c.category_name_ko, b.isbn, b.book_stock, b.created_at, b.updated_at, IFNULL(( SELECT SUM(oi.book_quantity) FROM orderitem oi WHERE oi.book_id = b.book_id ), 0) AS sales_count, IFNULL(( SELECT AVG(r.review_score) FROM review r WHERE r.book_id = b.book_id ), 0) AS average_rating, ( SELECT COUNT(*) FROM review r WHERE r.book_id = b.book_id ) AS review_count FROM book b LEFT JOIN category c ON b.category_id = c.category_id
b.status = '정상'
AND ( b.book_title LIKE CONCAT('%', #{search}, '%') OR b.author_name LIKE CONCAT('%', #{search}, '%') OR b.publisher LIKE CONCAT('%', #{search}, '%') )
AND b.category_id = #{category_id}
AND b.stock_status = #{stock_status}
ORDER BY sales_count DESC ORDER BY b.created_at DESC ORDER BY review_count DESC ORDER BY average_rating DESC ORDER BY b.book_id DESC
LIMIT #{pageStart}, #{perPageNum}

