SELECT b.book_id, b.book_title, b.author_name, b.publisher, b.publish_date, b.book_price, CASE WHEN b.book_stock = 0 THEN '품절' ELSE b.stock_status END AS stock_status, b.book_summary, b.cover_image, b.category_id, c.category_name_ko, b.isbn, b.book_stock, b.created_at, b.updated_at, b.status, IFNULL(SUM(oi.book_quantity), 0) AS sales_count, IFNULL(AVG(r.review_score), 0) AS average_rating, COUNT(r.review_id) AS review_count FROM book b LEFT JOIN orderitem oi ON b.book_id = oi.book_id LEFT JOIN review r ON b.book_id = r.book_id LEFT JOIN category c ON b.category_id = c.category_id
1 = 1
AND ( b.book_title LIKE CONCAT('%', #{search}, '%') OR b.author_name LIKE CONCAT('%', #{search}, '%') OR b.publisher LIKE CONCAT('%', #{search}, '%') )
AND b.category_id = #{category_id}
AND b.stock_status = #{stock_status}
GROUP BY b.book_id
ORDER BY (b.status = '삭제됨') ASC, sales_count DESC ORDER BY (b.status = '삭제됨') ASC, b.created_at DESC ORDER BY (b.status = '삭제됨') ASC, review_count DESC ORDER BY (b.status = '삭제됨') ASC, average_rating DESC ORDER BY (b.status = '삭제됨') ASC, b.book_id DESC
LIMIT #{pageStart}, #{perPageNum}

